// Helper functions
func getInitials(name string) string {
	parts := strings.Split(strings.TrimSpace(name), " ")
	if len(parts) >= 2 && len(parts[0]) > 0 && len(parts[len(parts)-1]) > 0 {
		return strings.ToUpper(string(parts[0][0]) + string(parts[len(parts)-1][0]))
	}
	if len(parts) == 1 && len(parts[0]) > 0 {
		return strings.ToUpper(string(parts[0][0]))
	}
	return "?"
}

func getObservationAtIndex(events []TimelineEventItem, index int) *TimelineEventItem {
	count := 0
	for i := range events {
		if events[i].Type == "observation" {
			if count == index {
				return &events[i]
			}
			count++
		}
	}
	return nil
}

func formatFullIdentity(gender, ethnicity, occupation, education string) string {
	var parts []string

	switch gender {
	case "m":
		parts = append(parts, "Masculino")
	case "f":
		parts = append(parts, "Feminino")
	case "o":
		parts = append(parts, "Outro")
	}

	switch ethnicity {
	case "b":
		parts = append(parts, "Branca")
	case "p":
		parts = append(parts, "Preta")
	case "m":
		parts = append(parts, "Parda")
	case "a":
		parts = append(parts, "Amarela")
	case "i":
		parts = append(parts, "Indígena")
	}

	if occupation != "" {
		parts = append(parts, occupation)
	}

	switch education {
	case "e":
		parts = append(parts, "Ensino Fundamental")
	case "m":
		parts = append(parts, "Ensino Médio")
	case "s":
		parts = append(parts, "Ensino Superior")
	case "p":
		parts = append(parts, "Pós-graduação")
	}

	return strings.Join(parts, " · ")
}

func formatMonthYear(t time.Time) string {
	months := []string{"jan", "fev", "mar", "abr", "mai", "jun", "jul", "ago", "set", "out", "nov", "dez"}
	return months[t.Month()-1] + "/" + strconv.Itoa(t.Year())
}

func calculateTherapyTime(createdAt time.Time) string {
	months := int(time.Since(createdAt).Hours() / 24 / 30)
	if months < 1 {
		return "<1m"
	}
	if months < 12 {
		return fmt.Sprintf("%dm", months)
	}
	years := float64(months) / 12.0
	return fmt.Sprintf("%.1fa", years)
}

func hasObservations(events []TimelineEventItem) bool {
	for _, event := range events {
		if event.Type == "observation" {
			return true
		}
	}
	return false
}

